// ─── Theme Library ───────────────────────────────────────────────────────────
// 1000+ curated themes for the IIC Educational Platform

export type ThemeCategory = 'STUDY' | 'AMOLED' | 'REWARD' | 'EVENT' | 'PREMIUM';
export type ThemeRarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY';

export interface ThemeColors {
  bgColor: string;
  topBarStart: string;
  topBarEnd: string;
  navBg: string;
  navActive: string;
  navBorder: string;
  cardBg: string;
  cardBorder: string;
  btnStart: string;
  btnEnd: string;
  textPrimary: string;
  textSecondary: string;
  accentGlow: string;
  progressColor: string;
}

export interface AppTheme {
  id: string;
  name: string;
  emoji: string;
  category: ThemeCategory;
  description: string;
  colors: ThemeColors;
  topBarEffect?: string;
  animColor?: string;
  animSpeed?: number;
  unlockLevel?: number;
  tags: string[];
  isAnimated: boolean;
  rarity: ThemeRarity;
  applyProfileBg?: boolean;
  applyAppBg?: boolean;
}

function h2r(hex: string): [number, number, number] {
  const h = hex.replace('#', '').padEnd(6, '0');
  return [parseInt(h.slice(0, 2), 16), parseInt(h.slice(2, 4), 16), parseInt(h.slice(4, 6), 16)];
}
function r2h(r: number, g: number, b: number): string {
  return '#' + [r, g, b].map(v => Math.min(255, Math.max(0, Math.round(v))).toString(16).padStart(2, '0')).join('');
}
function dk(hex: string, f: number) { const [r,g,b]=h2r(hex); return r2h(r*f,g*f,b*f); }

type BgStyle = 'dark' | 'amoled' | 'warm' | 'cool' | 'neutral' | 'deep';

function mc(accent: string, bg: BgStyle = 'dark', accent2?: string, ov?: Partial<ThemeColors>): ThemeColors {
  const [r,g,b] = h2r(accent);
  const a2 = accent2 || dk(accent, 0.75);
  const bgColor =
    bg === 'amoled'  ? '#000000' :
    bg === 'warm'    ? r2h(Math.max(3,r*0.06), Math.max(2,g*0.04), Math.max(2,b*0.04)) :
    bg === 'cool'    ? r2h(Math.max(2,r*0.04), Math.max(3,g*0.05), Math.max(4,b*0.08)) :
    bg === 'deep'    ? r2h(Math.max(2,r*0.04), Math.max(2,g*0.04), Math.max(2,b*0.04)) :
    bg === 'neutral' ? r2h(Math.max(5,r*0.07), Math.max(5,g*0.07), Math.max(5,b*0.07)) :
                       r2h(Math.max(3,r*0.05), Math.max(3,g*0.05), Math.max(3,b*0.05));
  const tsStart = r2h(Math.max(4,r*0.28), Math.max(4,g*0.28), Math.max(4,b*0.28));
  const tsEnd   = r2h(Math.max(2,r*0.16), Math.max(2,g*0.16), Math.max(2,b*0.16));
  const navBg   = bg === 'amoled' ? '#000000' : r2h(Math.max(4,r*0.07), Math.max(4,g*0.07), Math.max(4,b*0.07));
  const cardBg  = r2h(Math.max(6,r*0.09), Math.max(6,g*0.09), Math.max(6,b*0.09));
  return {
    bgColor, topBarStart: tsStart, topBarEnd: tsEnd,
    navBg, navActive: accent, navBorder: `rgba(${r},${g},${b},0.25)`,
    cardBg, cardBorder: `rgba(${r},${g},${b},0.18)`,
    btnStart: accent, btnEnd: a2,
    textPrimary: '#f1f5f9', textSecondary: `rgba(${Math.min(255,r+110)},${Math.min(255,g+110)},${Math.min(255,b+110)},0.75)`,
    accentGlow: accent, progressColor: accent,
    ...ov,
  };
}

// ── Seed format: [id,name,emoji,cat,accent,accent2,bgStyle,desc,effect?,animColor?,rarity,unlockLevel?,tags] ──
type Seed = [string,string,string,ThemeCategory,string,string,BgStyle,string,string?,string?,ThemeRarity,number?,string[]?];

function fromSeed(s: Seed): AppTheme {
  const [id,name,emoji,category,accent,accent2,bgStyle,description,effect,animColor,rarity,unlockLevel,tags] = s;
  return {
    id, name, emoji, category, description, rarity,
    colors: mc(accent, bgStyle, accent2),
    topBarEffect: effect,
    animColor: animColor || accent,
    animSpeed: 1,
    unlockLevel: unlockLevel || 0,
    tags: tags || [],
    isAnimated: !!effect,
  };
}

