// Build all themes
export const ALL_THEMES: AppTheme[] = [
  ...STUDY_SEEDS.map(fromSeed),
  ...AMOLED_SEEDS.map(fromSeed),
  ...REWARD_SEEDS.map(fromSeed),
  ...EVENT_SEEDS.map(fromSeed),
  ...PREMIUM_SEEDS.map(fromSeed),
];

export const THEME_CATEGORIES: { id: ThemeCategory; label: string; emoji: string; desc: string }[] = [
  { id: 'STUDY',   label: 'Study',   emoji: '📚', desc: 'Calm & focus themes for learning' },
  { id: 'AMOLED',  label: 'AMOLED',  emoji: '🌑', desc: 'True black — battery saver' },
  { id: 'REWARD',  label: 'Reward',  emoji: '🏆', desc: 'Unlock by reaching levels' },
  { id: 'EVENT',   label: 'Event',   emoji: '🎉', desc: 'Festival & temporary themes' },
  { id: 'PREMIUM', label: 'Premium', emoji: '💎', desc: 'Rare animated premium themes' },
];

export const getThemesByCategory = (cat: ThemeCategory) => ALL_THEMES.filter(t => t.category === cat);
export const getThemeById = (id: string) => ALL_THEMES.find(t => t.id === id);
export const getAvailableThemes = (userLevel: number) =>
  ALL_THEMES.filter(t => !t.unlockLevel || t.unlockLevel <= userLevel);
